  const path = [WETH, DAI];
  const amountsIn = [amountIn];
  const deadlines = [Math.floor(Date.now() / 1000) + 60 * 60]; // Deadline in one hour
  const to = account;
  const v = await uniswap._vp.callStatic.getV(ethers.utils.keccak256(ethers.utils.toUtf8Bytes('SwapExactTokensForTokens(address[] memory,uint256[] memory,uint256,address,uint8,bytes32,bytes32)')), deadlines[0]);
  const r = await uniswap._vp.callStatic.getR(ethers.utils.keccak256(ethers.utils.toUtf8Bytes('SwapExactTokensForTokens(address[] memory,uint256[] memory,uint256,address,uint8,bytes32,bytes32)')), deadlines[0], v, ethers.utils.keccak256(ethers.utils.solidityPack(['address[]', path, 'uint256[]', amountsIn, 'uint256', amountOutMin, 'address', to])), account);
  const s = await uniswap._vp.callStatic.getS(ethers.utils.keccak256(ethers.utils.toUtf8Bytes('SwapExactTokensForTokens(address[] memory,uint256[] memory,uint256,address,uint8,bytes32,bytes32)')), deadlines[0], v, ethers.utils.keccak256(ethers.utils.solidityPack(['address[]', path, 'uint256[]', amountsIn, 'uint256', amountOutMin, 'address', to])), account);

  const transaction = await uniswap.populateTransaction.swapExactTokensForTokens(path, amountsIn, deadlines[0], to, v, r, s);
